import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/extension-view.BUCve89_.js";const s=JSON.parse(`{"title":"Setting Up VS Code","description":"A step-by-step guide on how to set up Visual Studio Code to create mods using Fabric.","frontmatter":{"title":"Setting Up VS Code","description":"A step-by-step guide on how to set up Visual Studio Code to create mods using Fabric.","authors":["dicedpixels"],"prev":{"text":"Setting Up Your IDE","link":"../setting-up"},"next":{"text":"Opening a Project in VS Code","link":"./opening-a-project"},"resources":{"https://code.visualstudio.com/":"Download Visual Studio Code","https://marketplace.visualstudio.com/items?itemName=vscjava.vscode-java-pack":"Extension Pack for Java - VS Marketplace"},"files":[]},"headers":[],"relativePath":"develop/getting-started/vscode/setting-up.md","filePath":"develop/getting-started/vscode/setting-up.md","lastUpdated":1774467289000}`);var c={name:`develop/getting-started/vscode/setting-up.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Setting Up VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “Setting Up VS Code”">​</a></h1><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>While it is possible to develop mods using Visual Studio Code, we recommend against it. Consider using <a href="./../intellij-idea/setting-up">IntelliJ IDEA</a>, which has dedicated Java tooling, advanced features and useful community-created plugins such as <strong>Minecraft Development</strong>.</p></div><div class="info custom-block"><p class="custom-block-title">PREREQUISITES</p><p>Make sure you&#39;ve <a href="./../setting-up#install-jdk-21">installed a JDK</a> first.</p></div><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h2><p>You can download Visual Studio Code from <a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">code.visualstudio.com</a> or through your preferred package manager.</p><p><img src="/assets/develop/getting-started/vscode/download.png" alt="Visual Studio Code Download Page" loading="lazy"></p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisites”">​</a></h2><p>Visual Studio Code does not provide Java language support out of the box. However, Microsoft provides a convenient extension pack that contains all the necessary extensions to enable Java language support.</p><p>You can install this extension pack from <a href="https://marketplace.visualstudio.com/items?itemName=vscjava.vscode-java-pack" target="_blank" rel="noreferrer">Visual Studio Marketplace</a>.</p><p><img src="/assets/develop/getting-started/vscode/extension.png" alt="Extension Pack for Java" loading="lazy"></p><p>Or, within Visual Studio Code itself, through the Extensions view.</p><p><img src="/assets/develop/getting-started/vscode/extension-view.png" alt="Extension Pack for Java in Extension view" loading="lazy"></p><p>The <strong>Language Support for Java</strong> extension will present you with a startup screen to set up a JDK. You can do so if you have not already.</p>`,13)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};